@sealed
class HavenCoreImpl extends RustOpaque implements HavenCore {
  // Not to be used by end users
  HavenCoreImpl.frbInternalDcoDecode(List<dynamic> wire)
    : super.frbInternalDcoDecode(wire, _kStaticData);

  // Not to be used by end users
